const input = $input.first().json;
const urls = (input.url_list || '').split('\n').map(u => u.trim()).filter(u => u.length > 0);
if (urls.length === 0) return [{ json: { ...input, url_contents: '' } }];
return urls.map(url => ({ json: { ...input, fetch_url: 'https://r.jina.ai/' + url, source_url: url } }));

const items = $input.all();
const base = $('입력값 파싱').first().json;
let urlContents = '';
for (const item of items) {
  if (!item.json.fetch_url) continue;
  const content = (item.json.data || item.json.body || '').substring(0, 3000);
  if (content) urlContents += '[출처: ' + item.json.source_url + ']\n' + content + '\n\n---\n\n';
}
return [{ json: { ...base, url_contents: urlContents } }];

const d = $input.first().json;
const prev = $('1차 프롬프트 조립').first().json;
let raw = '';
if (d.candidates && d.candidates[0]) raw = d.candidates[0]['content']['parts'][0]['text'] || '';
raw = raw.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
let title = '[Blog] ' + prev.blog_topic, body = raw, hashtags = '';
try {
  const p = JSON.parse(raw);
  title = p.title || title;
  body = p.body || raw;
  if (Array.isArray(p.hashtags)) hashtags = p.hashtags.join(' ');
  else hashtags = p.hashtags || '';
} catch(e) {}
return [{ json: { ...prev, draft_content: body, draft_title: title, draft_hashtags: hashtags } }];

