const d = $input.first().json;
const prompt = '블로그 품질 평가자야. 아래 기준으로 평가 후 JSON만 반환해 (백틱 없이): {"passed":true,"score":0,"improvements":""}

평가기준:
(1) 본문 1500자 이상
(2) 소제목 4개 이상
(3) 구체적 예시 또는 팁 포함
(4) SEO 키워드 포함 (동탄수학학원 등)
(5) 독자 행동 유도 문구 포함
(6) 해시태그 15개 이상
5개 이상 충족 시 passed:true, improvements는 미달 항목 개선 방향

[평가할 글]
제목: ' + d.draft_title + '

' + (d.draft_content || '').slice(0, 1000);
const body = JSON.stringify({
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { temperature: 0.2, maxOutputTokens: 400 }
});
return [{ json: { ...d, eval_body: body } }];

const item = $input.first().json;
const prev = $('품질평가 프롬프트 조립').first().json;
let raw = '';
if (item.json && item.json.candidates && item.json.candidates[0]) raw = item.json.candidates[0]['content']['parts'][0]['text'] || '{}';
else if (item.candidates && item.candidates[0]) raw = item.candidates[0]['content']['parts'][0]['text'] || '{}';
raw = raw.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
let q = {};
try { q = JSON.parse(raw); } catch(e) { q = { passed: true, score: 70, improvements: '' }; }
return [{ json: { ...prev, quality_passed: q.passed || false, quality_score: q.score || 0, improvements: q.improvements || '' } }];

const d = $input.first().json;
const prev = $('3차 프롬프트 조립').first().json;
let raw = '';
if (d.candidates && d.candidates[0]) raw = d.candidates[0]['content']['parts'][0]['text'] || '';
raw = raw.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
let title = prev.draft_title, body = raw, hashtags = prev.draft_hashtags;
try {
  const p = JSON.parse(raw);
  title = p.title || title;
  body = p.body || raw;
  if (Array.isArray(p.hashtags)) hashtags = p.hashtags.join(' ');
  else hashtags = p.hashtags || hashtags;
} catch(e) {}
const MAX = 1900;
const bodyChunks = [];
for (let i = 0; i < body.length; i += MAX) bodyChunks.push(body.slice(i, i + MAX));
return [{ json: { ...prev, draft_content: body, bodyChunks, draft_title: title, draft_hashtags: hashtags, final_stage: '3차(gemma-4-31b)' } }];

